import { MakeLogicType, actions, kea, key, listeners, path, props, reducers } from 'kea'

import { uniqueBy } from 'lib/utils/arrays'

export interface ObjectTagsLogicProps {
    id: string | number
    onChange?: (tags: string[]) => void
}

function cleanTag(tag?: string): string {
    // Same clean done in posthog/api/tagged_item.py on frontend to mitigate confusion on tag create.
    return (tag ?? '').trim().toLowerCase()
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface objectTagsLogicValues {
    editingTags: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface objectTagsLogicActions {
    setEditingTags: (editingTags: boolean) => {
        editingTags: boolean
    }
    setTags: (tags: string[]) => {
        tags: string[]
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface objectTagsLogicMeta {
    key: number | string
}

export type objectTagsLogicType = MakeLogicType<
    objectTagsLogicValues,
    objectTagsLogicActions,
    ObjectTagsLogicProps,
    objectTagsLogicMeta
>

export const objectTagsLogic = kea<objectTagsLogicType>([
    path(['lib', 'components', 'ObjectTags', 'objectTagsLogic']),
    props({} as ObjectTagsLogicProps),
    key((props) => props.id),
    actions({
        setTags: (tags: string[]) => ({ tags }),
        setEditingTags: (editingTags: boolean) => ({ editingTags }),
    }),
    reducers(() => ({
        editingTags: [
            false,
            {
                setEditingTags: (_, { editingTags }) => editingTags,
            },
        ],
    })),
    listeners(({ props }) => ({
        setTags: ({ tags }) => {
            const nextTags = uniqueBy(tags.map(cleanTag), (i) => i)
            props.onChange?.(nextTags)
        },
    })),
])
